const ASCII_CONTROLS = /[\u0000-\u001F\u007F]/;
const ENCODED_ASCII_CONTROLS = /%(?:0[0-9A-F]|1[0-9A-F]|7F)/i;
const EXPLICIT_SCHEME = /^[A-Za-z][A-Za-z0-9+.-]*:/;
const SAFE_SCHEMES = new Set(['http:', 'https:', 'mailto:', 'tel:']);
const TRUSTED_BASE = new URL('https://frontendatlas.invalid/');

export default function sanitizeHrefUrl(input) {
  if (input == null) return null;

  const raw = String(input);
  if (ASCII_CONTROLS.test(raw) || raw.includes('\\')) return null;

  const value = raw.trim();
  if (!value || ENCODED_ASCII_CONTROLS.test(value) || value.startsWith('//')) {
    return null;
  }

  const isExplicit = EXPLICIT_SCHEME.test(value);

  try {
    const parsed = isExplicit ? new URL(value) : new URL(value, TRUSTED_BASE);
    if (!SAFE_SCHEMES.has(parsed.protocol)) return null;

    if (!isExplicit) {
      if (parsed.protocol !== TRUSTED_BASE.protocol || parsed.origin !== TRUSTED_BASE.origin) {
        return null;
      }
      return value;
    }

    return parsed.href;
  } catch {
    return null;
  }
}
